// === TEST CASES ===
// TC1: input { param1: 10, param2: 2, param3: "weapon", param4: true } → output { total: 60, breakdown: { attack: 10, speed: 2, type: "weapon", typeMultiplier: 2, critical: true, criticalMultiplier: 1.5, baseDPS: 20, adjustedDPS: 40, powerScore: 60 } }
// TC2: input { param1: 5, param2: 1.5, param3: "armor", param4: false } → output { total: 3.75, breakdown: { attack: 5, speed: 1.5, type: "armor", typeMultiplier: 0.5, critical: false, criticalMultiplier: 1, baseDPS: 7.5, adjustedDPS: 3.75, powerScore: 3.75 } }
// TC3: input { param1: 20, param2: 1.2, param3: "accessory", param4: true } → output { total: 36, breakdown: { attack: 20, speed: 1.2, type: "accessory", typeMultiplier: 1, critical: true, criticalMultiplier: 1.5, baseDPS: 24, adjustedDPS: 24, powerScore: 36 } }
// TC4: input { param1: 1000, param2: 0.5, param3: "weapon", param4: false } → output { total: 1000, breakdown: ... }
// TC5: input { param1: 7.5, param2: 1.3, param3: "accessory", param4: false } → output { total: 9.75, breakdown: ... }
// TC6: input { param1: -5, param2: 2, param3: "weapon", param4: false } → output { error: "Attack must be > 0." }
// TC7: input { param1: 0, param2: 2, param3: "weapon", param4: false } → output { error: "Attack must be > 0." }
// TC8: input { param1: 10, param2: -1, param3: "weapon", param4: false } → output { error: "Speed must be > 0." }
// TC9: input { param1: "abc", param2: 2, param3: "weapon", param4: false } → output { error: "Attack must be a number." }
// TC10: input { param1: 10, param2: "", param3: "weapon", param4: false } → output { error: "Speed must be a number." }
// TC11: input { param1: 10, param2: 2, param3: "potion", param4: false } → output { error: "Invalid item type. Must be weapon, armor, or accessory." }
// TC12: input { param1: 10, param2: 2, param3: null, param4: false } → output { error: "Item type is required." }
// TC13: input { param1: 10, param2: 2, param3: "weapon" } (param4 omitted) → output { total: 40, breakdown: { ..., critical: false, criticalMultiplier: 1, ... } }
// TC14: input { param1: 10, param2: 2, param3: "weapon", param4: "yes" } → output { error: "Toggle must be a boolean." }
// TC15: input { param1: NaN, param2: 2, param3: "weapon", param4: false } → output { error: "Attack must be a number." }
// TC16: input { param1: 10, param2: Infinity, param3: "weapon", param4: false } → output { error: "Speed must be a finite number." }
// TC17: input { param1: 10, param2: 2, param3: "  weapon  ", param4: false } → output { total: 40, ... } (whitespace trimmed)
// TC18: input { param1: 10, param2: 2, param3: "", param4: false } → output { error: "Item type is required." }
// TC19: input { param1: 0.001, param2: 0.002, param3: "weapon", param4: true } → output { total: 0.000006, ... }
// TC20: calculator.formatCurrency(123.456) → "$123.46"

// === CALCULATOR ===
// Formula reference: Simplified DPS (damage per second) and power score used in many RPGs (e.g., Diablo, Path of Exile).
// Power Score = Attack * Speed * Type Multiplier * Critical Multiplier
// Type multipliers: weapon = 2.0, armor = 0.5, accessory = 1.0
// Critical multiplier = 1.5 if toggle on, else 1.0

const calculator = {
  calculate(inputs) {
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors[0] }; // return first error only
    }

    const attack = inputs.param1;
    const speed = inputs.param2;
    const itemType = inputs.param3.trim();
    const isCritical = inputs.param4 !== undefined ? inputs.param4 : false;

    const typeMultipliers = {
      weapon: 2,
      armor: 0.5,
      accessory: 1
    };
    const typeMultiplier = typeMultipliers[itemType];
    const critMultiplier = isCritical ? 1.5 : 1;

    const baseDPS = attack * speed;
    const adjustedDPS = baseDPS * typeMultiplier;
    const powerScore = adjustedDPS * critMultiplier;

    return {
      total: powerScore,
      breakdown: {
        attack: attack,
        speed: speed,
        type: itemType,
        typeMultiplier: typeMultiplier,
        critical: isCritical,
        criticalMultiplier: critMultiplier,
        baseDPS: baseDPS,
        adjustedDPS: adjustedDPS,
        powerScore: powerScore
      }
    };
  },

  validate(inputs) {
    const errors = [];
    const { param1, param2, param3, param4 } = inputs;

    // param1 validation
    if (param1 === undefined || param1 === null || typeof param1 !== 'number' || Number.isNaN(param1)) {
      errors.push("Attack must be a number.");
    } else if (!Number.isFinite(param1)) {
      errors.push("Attack must be a finite number.");
    } else if (param1 <= 0) {
      errors.push("Attack must be > 0.");
    }

    // param2 validation
    if (param2 === undefined || param2 === null || typeof param2 !== 'number' || Number.isNaN(param2)) {
      errors.push("Speed must be a number.");
    } else if (!Number.isFinite(param2)) {
      errors.push("Speed must be a finite number.");
    } else if (param2 <= 0) {
      errors.push("Speed must be > 0.");
    }

    // param3 validation
    if (param3 === undefined || param3 === null) {
      errors.push("Item type is required.");
    } else if (typeof param3 !== 'string') {
      errors.push("Item type must be a string.");
    } else {
      const trimmed = param3.trim();
      if (trimmed === "") {
        errors.push("Item type is required.");
      } else if (!["weapon", "armor", "accessory"].includes(trimmed)) {
        errors.push("Invalid item type. Must be weapon, armor, or accessory.");
      }
    }

    // param4 validation (optional, but if present must be boolean)
    if (param4 !== undefined && param4 !== null) {
      if (typeof param4 !== 'boolean') {
        errors.push("Toggle must be a boolean.");
      }
      // else true/false is valid, no further check
    }
    // if missing, default false in calculate

    return {
      valid: errors.length === 0,
      errors: errors
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },

  reset() {
    // example: clear any stored cached inputs if needed
    // but no-op since stateless
  },

  saveToLocalStorage(key, data) {
    try {
      if (typeof window !== 'undefined' && window.localStorage) {
        window.localStorage.setItem(key, JSON.stringify(data));
      }
    } catch (e) {
      // silently fail
    }
  },

  loadFromLocalStorage(key) {
    try {
      if (typeof window !== 'undefined' && window.localStorage) {
        const item = window.localStorage.getItem(key);
        return item ? JSON.parse(item) : null;
      }
    } catch (e) {
      return null;
    }
    return null;
  }
};
